import React, {useState} from 'react';
import {StyleSheet, View, useWindowDimensions} from 'react-native';
import {Canvas, Image as SkImage, useImage, Path, Skia, SkPath} from '@shopify/react-native-skia';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import {runOnJS} from 'react-native-reanimated';
export function ImageAnnotator({uri}: {uri: string}) {
  const {width: SW} = useWindowDimensions();
  const image = useImage(uri);
  const [paths, setPaths] = useState<SkPath[]>([]);
  const [current, setCurrent] = useState<SkPath | null>(null);
  const pan = Gesture.Pan().onStart(e => { const p = Skia.Path.Make(); p.moveTo(e.x, e.y); runOnJS(setCurrent)(p); }).onUpdate(e => { if (current) { current.lineTo(e.x, e.y); runOnJS(setCurrent)(current); }}).onEnd(() => { if (current) runOnJS(setPaths)([...paths, current]); runOnJS(setCurrent)(null); });
  return (<GestureDetector gesture={pan}><Canvas style={{width: SW, height: SW}}>{image && <SkImage image={image} x={0} y={0} width={SW} height={SW} fit='cover'/>}{paths.map((p, i) => <Path key={i} path={p} style='stroke' strokeWidth={4} color='#FF453A'/>)}{current && <Path path={current} style='stroke' strokeWidth={4} color='#FF453A'/>}</Canvas></GestureDetector>);
}

